class {{nama_class}}(html.parser.HTMLParser):
    """Extract text from HTML, skipping tags and scripts."""
    SKIP_TAGS = {'script', 'style', 'head'}

    def __init__(self):
        super().__init__()
        self._result = []
        self._skip_depth = 0

    def handle_starttag(self, tag, attrs):
        if tag.lower() in self.SKIP_TAGS:
            self._skip_depth += 1
        if tag.lower() in ('br', 'p', 'div', 'li', 'tr', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6'):
            self._result.append('\n')

    def handle_endtag(self, tag):
        if tag.lower() in self.SKIP_TAGS:
            self._skip_depth = max(0, self._skip_depth - 1)
        if tag.lower() in ('p', 'div', 'table', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6'):
            self._result.append('\n')

    def handle_data(self, data):
        if self._skip_depth == 0:
            self._result.append(data)

    def get_text(self):
        import re
        text = ''.join(self._result)
        text = re.sub(r'\n{3,}', '\n\n', text)
        return text.strip()


