def {{nama_fungsi}}(text, separator='\\n\\n', min_length=1):
    """Split text into paragraph blocks.
    separator: regex pattern for block boundaries (default: blank lines).
    min_length: minimum block length to include.
    """
    blocks = re.split(separator, text)
    return [b.strip() for b in blocks if len(b.strip()) >= min_length]


def {{nama_fungsi_chunks}}(text, max_chars=1000, overlap=100):
    """Split text into overlapping chunks by character count.
    Tries to break at sentence boundaries.
    """
    if len(text) <= max_chars:
        return [text]
    sentences = re.split(r'(?<=[.!?])\s+', text)
    chunks = []
    current = ''
    for sentence in sentences:
        if len(current) + len(sentence) + 1 > max_chars and current:
            chunks.append(current.strip())
            # Keep overlap
            if overlap > 0 and len(current) > overlap:
                current = current[-overlap:] + ' ' + sentence
            else:
                current = sentence
        else:
            current = (current + ' ' + sentence).strip()
    if current.strip():
        chunks.append(current.strip())
    return chunks
